/**
 * TaskInfoDialog — detailed task editing dialog (double-click a row).
 */

import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  FormControlLabel,
  Checkbox,
  Grid,
} from '@mui/material';

import { useProjectStore, useUIStore, type TaskRow } from '../../stores';
import { constraintLabel, isoDate } from '../../utils/format';

const CONSTRAINT_TYPES = [0, 1, 2, 3, 4, 5, 6, 7];

const TaskInfoDialog: React.FC = () => {
  const open = useUIStore((s) => s.openDialog === 'taskInfo');
  const payload = useUIStore((s) => s.dialogPayload) as TaskRow | null;
  const closeDialog = useUIStore((s) => s.closeDialog);
  const updateTask = useProjectStore((s) => s.updateTask);
  const showSnackbar = useUIStore((s) => s.showSnackbar);

  const [name, setName] = useState('');
  const [durationMinutes, setDurationMinutes] = useState(0);
  const [start, setStart] = useState('');
  const [finish, setFinish] = useState('');
  const [percentComplete, setPercentComplete] = useState(0);
  const [constraintType, setConstraintType] = useState(0);
  const [constraintDate, setConstraintDate] = useState('');
  const [isManuallyScheduled, setIsManuallyScheduled] = useState(false);
  const [notes, setNotes] = useState('');
  const [deadline, setDeadline] = useState('');

  useEffect(() => {
    if (payload) {
      setName(payload.name);
      setDurationMinutes(payload.durationMinutes);
      setStart(isoDate(payload.start));
      setFinish(isoDate(payload.finish));
      setPercentComplete(payload.percentComplete);
      setConstraintType(payload.constraintType);
      setConstraintDate(payload.constraintDate ? isoDate(payload.constraintDate) : '');
      setIsManuallyScheduled(payload.isManuallyScheduled);
      setNotes(payload.notes ?? '');
      setDeadline(payload.deadline ? isoDate(payload.deadline) : '');
    }
  }, [payload]);

  const handleSave = async () => {
    if (!payload) return;
    try {
      await updateTask(payload.id, {
        name,
        durationMinutes,
        start: new Date(start).toISOString(),
        finish: new Date(finish).toISOString(),
        percentComplete,
        constraintType,
        constraintDate: constraintDate
          ? new Date(constraintDate).toISOString()
          : null,
        isManuallyScheduled,
        notes: notes || null,
        deadline: deadline ? new Date(deadline).toISOString() : null,
      });
      closeDialog();
    } catch (e: any) {
      showSnackbar(e.message, 'error');
    }
  };

  return (
    <Dialog open={open} onClose={closeDialog} maxWidth="sm" fullWidth>
      <DialogTitle>Task Information</DialogTitle>
      <DialogContent>
        <Grid container spacing={2} sx={{ pt: 1 }}>
          <Grid size={12}>
            <TextField
              label="Task Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              fullWidth
              size="small"
            />
          </Grid>
          <Grid size={6}>
            <TextField
              label="Duration (minutes)"
              type="number"
              value={durationMinutes}
              onChange={(e) => setDurationMinutes(Number(e.target.value))}
              fullWidth
              size="small"
            />
          </Grid>
          <Grid size={6}>
            <TextField
              label="% Complete"
              type="number"
              value={percentComplete}
              onChange={(e) =>
                setPercentComplete(
                  Math.min(100, Math.max(0, Number(e.target.value))),
                )
              }
              fullWidth
              size="small"
            />
          </Grid>
          <Grid size={6}>
            <TextField
              label="Start"
              type="date"
              value={start}
              onChange={(e) => setStart(e.target.value)}
              fullWidth
              size="small"
              slotProps={{ inputLabel: { shrink: true } }}
            />
          </Grid>
          <Grid size={6}>
            <TextField
              label="Finish"
              type="date"
              value={finish}
              onChange={(e) => setFinish(e.target.value)}
              fullWidth
              size="small"
              slotProps={{ inputLabel: { shrink: true } }}
            />
          </Grid>
          <Grid size={6}>
            <FormControl size="small" fullWidth>
              <InputLabel>Constraint</InputLabel>
              <Select
                value={constraintType}
                onChange={(e) => setConstraintType(Number(e.target.value))}
                label="Constraint"
              >
                {CONSTRAINT_TYPES.map((c) => (
                  <MenuItem key={c} value={c}>
                    {constraintLabel(c)}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
          <Grid size={6}>
            <TextField
              label="Constraint Date"
              type="date"
              value={constraintDate}
              onChange={(e) => setConstraintDate(e.target.value)}
              fullWidth
              size="small"
              slotProps={{ inputLabel: { shrink: true } }}
              disabled={constraintType === 0 || constraintType === 1}
            />
          </Grid>
          <Grid size={6}>
            <TextField
              label="Deadline"
              type="date"
              value={deadline}
              onChange={(e) => setDeadline(e.target.value)}
              fullWidth
              size="small"
              slotProps={{ inputLabel: { shrink: true } }}
            />
          </Grid>
          <Grid size={6}>
            <FormControlLabel
              control={
                <Checkbox
                  checked={isManuallyScheduled}
                  onChange={(e) => setIsManuallyScheduled(e.target.checked)}
                  size="small"
                />
              }
              label="Manually Scheduled"
            />
          </Grid>
          <Grid size={12}>
            <TextField
              label="Notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              fullWidth
              size="small"
              multiline
              rows={3}
            />
          </Grid>
        </Grid>
      </DialogContent>
      <DialogActions>
        <Button onClick={closeDialog}>Cancel</Button>
        <Button variant="contained" onClick={handleSave}>
          Save
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default TaskInfoDialog;
